Hi @Stephen-Hazel!

Maybe the modification (from [this Stackoverflow answer](http://stackoverflow.com/a/13641884/145346)) will work better...

Add the following code outside of the document ready function, and after the editable widget is loaded:

```js
$.tablesorter.editable.selectAll = function( cell ) {
	setTimeout( function() {
		// select all text in contenteditable
		// see http://stackoverflow.com/a/13641884/145346
		var range, selection;
		if ( document.body.createTextRange ) {
			range = document.body.createTextRange();
			range.moveToElementText( cell );
			range.select();
		} else if ( window.getSelection ) {
			selection = window.getSelection();
			range = document.createRange();
			range.selectNodeContents( cell );
			selection.removeAllRanges();
			selection.addRange( range );
		}
	}, 100 );
};
```

