```Python
    def __init__(self, data):
        for k, v in data.items():
            if isinstance(v, dict):
                setattr(self, camel_to_snake(k), TelemetryObject(v, k))
            elif isinstance(v, list):
                setattr(self, camel_to_snake(k), [TelemetryObject(e, k) for e in v])
            elif k in ("_D", "_T", "_V"):
                setattr(self, k, v)
            elif k == "blueZoneCustomOptions":  # serialized json
                if len(v) > 2:  # more than just '[]'
                    tmp = json.loads(v)
                    for i in tmp:
                        setattr(self, camel_to_snake(k), TelemetryObject(i, k))
                else:
                    setattr(self, camel_to_snake(k), json.loads(v))
            else:
                setattr(self, camel_to_snake(k), v)
```

I don't know when the above PR will be accepted, so if you need a workaround you can do something like this:

from consul import Consul
from consul.base import CB


class MyAgentService(Consul.Agent.Service):
    def deregister(self, service_id):
        return self.agent.http.put(CB.bool(), '/v1/agent/service/deregister/%s' % service_id)


consul = Consul(host=host, port=port)
consul.agent.service = MyAgentService(consul)

This will override the "bad" deregister method and use put instead of get.

