c++ -std=c++14 -Os -I/usr/include/python3.6m -I. myclone.cpp -shared -fPIC -o myclone.cpython-36m-x86_64-linux-gnu.so
jagerman@betwixt:~/src/pybind11/scratch⦗upstream✻$⦘$ python3 pyclone.py 
<class '__main__.MyFoobar'>
Woof!
